# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

import groovy.cli.commons.CliBuilder
pipeline {
    agent any
    
    stages { 
        stage('Build'){  
            steps{     
                script{        
                    def dockerImage = '' + env.DOCKER_IMAGE       // get the image tag from environment variable DOCKER_IMAGE (user-provided)         
                    def registryUrl=''+env.REGISTRY_URL        //get url of repository  user provided by team  
                    
                   withCredentials([usernamePassword(credentialsId: 'dockerhub', usernameVariable:'USERNAME', passwordVariable:'PASSWORD')]) {        
                        sh "echo ${ credentialsId }"       //prints the credential id     
                    echo """  docker build -t  $DOCKER_IMAGE .   ## Building Docker image"""    
                         runDockerBuild(dockerImage, registryUrl)   
                   }}       
                }        
            }         
          
             def runDockerBuild (String DOCKER_TAG , String REGISTRY){       //function to build and push the docker images     
                 echo """  docker login -u $USERNAME -p  $PASSWORD   $REGISTRY"""     #logging into registry   
                  sh "docker build -t $DOCKER_IMAGE . && docker push ${ DOCKER_IMAGE }"   //building and pushing the image to repository     
             }} 
        }      
         stage('Test') {         
            steps{              echo 'Running tests...'           #running test cases here if any    
                script{               sh "echo Testing..."   
                    runDockerBuild(dockerImage, registryUrl)   //call the function to build and push image      }       }} 
        }        
}